mapper.select:
where p.del_flag = '0'
and ( p.system_spu_code like concat('%', #{keyword}, '%') or p.seller_spu_code like concat('%', #{keyword}, '%') or p.product_name like concat('%', #{keyword}, '%') or p.product_name_en like concat('%', #{keyword}, '%') or exists ( select 1 from product_sku sk where sk.spu_id = p.spu_id and sk.del_flag = '0' and (sk.system_sku_code like concat('%', #{keyword}, '%') or sk.seller_sku_code like concat('%', #{keyword}, '%')) ) )
and p.system_spu_code like concat('%', #{systemSpuCode}, '%')
and p.seller_spu_code like concat('%', #{sellerSpuCode}, '%')
and p.product_name like concat('%', #{productName}, '%')
and p.product_name_en like concat('%', #{productNameEn}, '%')
and p.seller_id = #{sellerId}
and p.category_id = #{categoryId}
and wh.warehouse_kind_summary = #{warehouseKindSummary}
and p.spu_status = #{spuStatus}
and p.control_status = #{controlStatus}
and exists ( select 1 from product_sku sk where sk.spu_id = p.spu_id and sk.del_flag = '0' and sk.system_sku_code like concat('%', #{systemSkuCode}, '%') )
and exists ( select 1 from product_sku sk where sk.spu_id = p.spu_id and sk.del_flag = '0' and sk.seller_sku_code like concat('%', #{sellerSkuCode}, '%') )
order by p.update_time desc, p.spu_id desc


where p.spu_id = #{spuId}
  and p.del_flag = '0'
limit 1


where p.spu_id = #{spuId}
  and p.seller_id = #{sellerId}
  and p.del_flag = '0'
limit 1

select count(1)
from product_spu
where seller_id = #{sellerId}
  and seller_spu_code = #{sellerSpuCode}
  and seller_spu_code <> ''
  and del_flag = '0'

    and spu_id <> #{excludeSpuId}

select sk.*, p.system_spu_code, p.seller_spu_code, p.seller_name, p.category_id, p.category_name, p.product_name, p.product_name_en, p.spu_status, p.control_status as spu_control_status, wh.warehouse_kind_summary, , ,
from product_sku sk inner join product_spu p on p.spu_id = sk.spu_id and p.del_flag = '0' left join ( select spu_id, case when count(distinct warehouse_kind) = 1 then min(warehouse_kind) else 'MIXED' end as warehouse_kind_summary from product_spu_warehouse group by spu_id ) wh on wh.spu_id = sk.spu_id
where sk.del_flag = '0'
and ( sk.system_sku_code like concat('%', #{keyword}, '%') or sk.seller_sku_code like concat('%', #{keyword}, '%') or p.system_spu_code like concat('%', #{keyword}, '%') or p.seller_spu_code like concat('%', #{keyword}, '%') or p.product_name like concat('%', #{keyword}, '%') or p.product_name_en like concat('%', #{keyword}, '%') )
and sk.system_sku_code like concat('%', #{systemSkuCode}, '%')
and sk.seller_sku_code like concat('%', #{sellerSkuCode}, '%')
and p.system_spu_code like concat('%', #{systemSpuCode}, '%')
and p.seller_spu_code like concat('%', #{sellerSpuCode}, '%')
and ( p.product_name like concat('%', #{productName}, '%') or p.product_name_en like concat('%', #{productName}, '%') )
and sk.seller_id = #{sellerId}
and p.category_id = #{categoryId}
and b.master_sku like concat('%', #{masterSku}, '%')
and wh.warehouse_kind_summary = #{warehouseKindSummary}
and sku_inventory.inventory_status = #{inventoryStatus}
and p.spu_status = #{spuStatus}
and sk.sku_status = #{skuStatus}
and sk.control_status = #{controlStatus} and p.control_status = #{controlStatus}
and (sk.control_status = 'DISABLED' or p.control_status = 'DISABLED')
order by coalesce(sk.update_time, sk.create_time) desc, sk.sku_id desc

select count(1)
from product_sku
where seller_id = #{sellerId}
  and seller_sku_code = #{sellerSkuCode}
  and seller_sku_code <> ''
  and del_flag = '0'

    and sku_id <> #{excludeSkuId}

select sk.spu_id as spuId, sk.sku_id as skuId, sk.seller_id as sellerId, p.seller_no as sellerNo, p.seller_name as sellerName, p.system_spu_code as systemSpuCode, p.seller_spu_code as sellerSpuCode, sk.system_sku_code as systemSkuCode, sk.seller_sku_code as sellerSkuCode, p.product_name as productName, p.product_name_en as productNameEn, p.main_image_url as mainImageUrl, sk.sku_image_url as skuImageUrl, sk.color, sk.size, sk.model from product_sku sk join product_spu p on p.spu_id = sk.spu_id and p.del_flag = '0' where sk.del_flag = '0' and sk.sku_id in
#{skuId}
order by sk.sku_id asc

select distinct sk.spu_id from product_sku sk join product_sku_source_binding b on b.sku_id = sk.sku_id and b.binding_status = 'ACTIVE' where sk.del_flag = '0' and (
(b.source_scope = #{sourceKey.sourceScope} and b.master_sku = #{sourceKey.masterSku} and coalesce(b.master_product_name_snapshot, '') = coalesce(#{sourceKey.masterProductName}, ''))
) order by sk.spu_id asc
